+// =============================================================================
+// Thread-Safe Model Cache
+// =============================================================================
+// Prevents double model loading by caching loaded models.
+// Uses reference counting for safe cleanup.
+
+const CachedModel = struct {
+    handle: *c.llama_model,
+    ref_count: std.atomic.Value(u32),
+    path_hash: u64,
+    gpu_layers: i32,
+};
+
+/// Global model cache with mutex protection
+var model_cache: struct {
+    mutex: std.Thread.Mutex = .{},
+    entries: [4]?CachedModel = .{ null, null, null, null }, // Max 4 cached models
+    initialized: bool = false,
+} = .{};
+
+/// Get or load a model from cache (thread-safe)
+fn getCachedModel(path: []const u8, opts: ModelOptions) !*c.llama_model {
+    const path_hash = std.hash.Wyhash.hash(0, path);
+
+    model_cache.mutex.lock();
+    defer model_cache.mutex.unlock();
+
+    // Check if already cached
+    for (&model_cache.entries) |*entry| {
+        if (entry.*) |*cached| {
+            if (cached.path_hash == path_hash and cached.gpu_layers == opts.n_gpu_layers) {
+                // Found cached model, increment ref count
+                _ = cached.ref_count.fetchAdd(1, .monotonic);
+                return cached.handle;
+            }
+        }
+    }
+
+    // Not cached, need to load
+    // Initialize llama backend (once)
+    if (!model_cache.initialized) {
+        c.llama_backend_init();
+        model_cache.initialized = true;
+    }
+
+    var params = c.llama_model_default_params();
+    params.n_gpu_layers = opts.n_gpu_layers;
+    params.use_mmap = opts.use_mmap;
+    params.use_mlock = opts.use_mlock;
+    params.vocab_only = opts.vocab_only;
+
+    // Create null-terminated path
+    var path_buf: [4096]u8 = undefined;
+    if (path.len >= path_buf.len) return error.PathTooLong;
+    @memcpy(path_buf[0..path.len], path);
+    path_buf[path.len] = 0;
+
+    const model = c.llama_model_load_from_file(&path_buf, params);
+    if (model == null) {
+        return error.FailedToLoadModel;
+    }
+
+    // Find empty slot in cache
+    for (&model_cache.entries) |*entry| {
+        if (entry.* == null) {
+            entry.* = CachedModel{
+                .handle = model.?,
+                .ref_count = std.atomic.Value(u32).init(1),
+                .path_hash = path_hash,
+                .gpu_layers = opts.n_gpu_layers,
+            };
+            return model.?;
+        }
+    }
+
+    // Cache full, find LRU entry (lowest ref count) to evict
+    var min_idx: usize = 0;
+    var min_refs: u32 = std.math.maxInt(u32);
+    for (model_cache.entries, 0..) |entry, i| {
+        if (entry) |cached| {
+            const refs = cached.ref_count.load(.monotonic);
+            if (refs < min_refs) {
+                min_refs = refs;
+                min_idx = i;
+            }
+        }
+    }
+
+    // Only evict if ref count is 0
+    if (model_cache.entries[min_idx]) |*old| {
+        if (old.ref_count.load(.monotonic) == 0) {
+            c.llama_model_free(old.handle);
+            model_cache.entries[min_idx] = CachedModel{
+                .handle = model.?,
+                .ref_count = std.atomic.Value(u32).init(1),
+                .path_hash = path_hash,
+                .gpu_layers = opts.n_gpu_layers,
+            };
+            return model.?;
+        }
+    }
+
+    // Cache full with active models - store without caching
+    // This handles the rare case of >4 simultaneous models
+    return model.?;
+}
+
+/// Release a cached model reference (thread-safe)
+fn releaseCachedModel(handle: *c.llama_model) void {
+    model_cache.mutex.lock();
+    defer model_cache.mutex.unlock();
+
+    for (&model_cache.entries) |*entry| {
+        if (entry.*) |*cached| {
+            if (cached.handle == handle) {
+                const prev = cached.ref_count.fetchSub(1, .monotonic);
+                // Free immediately when ref count reaches 0 to avoid Metal cleanup issues
+                if (prev == 1) {
+                    c.llama_model_free(cached.handle);
+                    entry.* = null;
+                }
+                return;
+            }
+        }
+    }
+
+    // Not in cache (overflow model), free immediately
+    c.llama_model_free(handle);
+}
+
+/// Clean up all cached models (call at program exit)
+pub fn cleanupModelCache() void {
+    model_cache.mutex.lock();
+    defer model_cache.mutex.unlock();
+
+    for (&model_cache.entries) |*entry| {
+        if (entry.*) |*cached| {
+            c.llama_model_free(cached.handle);
+            entry.* = null;
+        }
+    }
+}
